+
+function pathMatches(paths: Set<string>, pattern: string): boolean {
+  if (pattern.endsWith("/")) {
+    for (const path of paths) {
+      if (path.startsWith(pattern)) return true;
+    }
+    return false;
+  }
+  return paths.has(pattern);
+}
